        model = models.Item

    barcode = factory.fuzzy.FuzzyText(length=10)

class OrderHdrFactory(factory.DjangoModelFactory):
    order_nbr = factory.fuzzy.FuzzyText(length=20)
    class Meta:
        model = models.OrderHdr

    @factory.post_generation
    def order_dtls(self, create, extracted, **kwargs):
        if not create:
            return

        if extracted is not None:
            for order_dtl in extracted:
                order_dtl.order = self
                author.save()
            return
        for _ in range(5):
            OrderDtlFactory(order=self,
                            **kwargs)

class WorkOrderKitFactory(factory.DjangoModelFactory):
    class Meta:
        model = models.WorkOrderKit
    
    work_order_nbr = factory.fuzzy.FuzzyText(length=20)
    item = SubFactory(ItemFactory)
    sales_order = SubFactory(OrderHdrFactory,
                             order_dtls__item=SelfAttribute("..item"))

class OrderDtlFactory(factory.DjangoModelFactory):
    class Meta:
        model = models.OrderDtl

    order = SubFactory(OrderHdrFactory,
                       order_dtls=[])
    item = SubFactory(ItemFactory)

Hi Torsten,

in the current implementation, during every call of 'simulate_fmu()', the fmu is unzipped, intialized and after the run terminated and the temporary folder is deleted. 
This is problematic for several (thousand) runs with the same fmu, e.g. Monte-Carlo. Would it be possible to re-structure and split the simulation in a init-, a run- and a terminate call, e.g. as a class:
```python
class simulate_with_fmu(object):

   def __init__(self):
     unzipdir = extract(filename)
     fmu.initialize()
     ...

   def run():
      return simulateME()

   def __exit__(self):
       fmu.terminate()
       fmu.freeInstance()
       shutil.rmtree(unzipdir)
```
